export const npContentExpansionMiscLessons: Record<string, LessonContent> = {
  // === GERIATRICS CORE (+2 to reach 8) ===
  "geriatrics-beers-criteria-np": {
    title: "Beers Criteria: Potentially Inappropriate Medications in Older Adults",
    cellular: { title: "Clinical Foundation", content: "The American Geriatrics Society (AGS) Beers Criteria is the most widely used explicit list of potentially inappropriate medications (PIMs) for older adults ≥65 years. Updated every 3 years, the Beers list identifies medications with unfavorable risk-benefit ratios in older adults due to age-related pharmacokinetic changes (reduced hepatic metabolism, decreased renal clearance, increased body fat, decreased lean mass, reduced albumin) and pharmacodynamic changes (increased sensitivity to CNS-active drugs, impaired baroreceptor reflexes). Key categories: (1) PIMs to AVOID regardless of diagnosis: first-generation antihistamines (diphenhydramine — anticholinergic, causes confusion and falls), benzodiazepines (increased fall risk, cognitive impairment, paradoxical agitation), long-acting sulfonylureas (glyburide — hypoglycemia risk), meperidine (neurotoxic metabolite normeperidine), skeletal muscle relaxants (cyclobenzaprine, methocarbamol — sedation, anticholinergic burden); (2) PIMs to AVOID with specific conditions: NSAIDs with CKD or heart failure, anticholinergics with dementia, benzodiazepines with falls history; (3) Drug-drug interactions: concurrent anticholinergic medications (cumulative anticholinergic burden), opioids + benzodiazepines (respiratory depression); (4) Medications requiring dose adjustment: renal-dosed medications, digoxin (target 0.5-0.9 ng/mL in elderly, not 1.0-2.0). The NP conducts systematic medication reconciliation at every visit using the Beers Criteria and anticholinergic burden scales (ACB, ADS) to identify and deprescribe PIMs, replacing them with safer alternatives." },
    riskFactors: ["Age ≥65 years with polypharmacy (≥5 chronic medications — prevalence >40% in community-dwelling elderly)", "Cognitive impairment or dementia (increased sensitivity to anticholinergic and sedating medications)", "Fall history (benzodiazepines, opioids, anticholinergics, antihypertensives increase fall risk)", "Chronic kidney disease (many medications require dose reduction or avoidance)", "Heart failure (NSAIDs, nondihydropyridine CCBs, dronedarone are contraindicated)", "Insomnia in elderly (benzodiazepines and Z-drugs [zolpidem, zaleplon] are PIMs — use CBT-I first-line)", "Pain management in elderly (meperidine, chronic NSAIDs, muscle relaxants are PIMs)"],
    diagnostics: ["Comprehensive medication reconciliation at every encounter (including OTC, supplements, and herbal medications)", "Anticholinergic Cognitive Burden (ACB) scale scoring (cumulative score ≥3 associated with cognitive decline and delirium)", "Renal function (CKD-EPI eGFR for dose adjustment of renally cleared medications)", "Orthostatic vital signs (lying and standing BP — identify medications contributing to orthostatic hypotension)", "Fall risk assessment (Timed Up and Go test, medication-related fall risk screening)", "Cognitive screening (MMSE, MoCA — assess for medication-induced cognitive impairment)", "Pharmacy claims review or electronic health record medication alerts for Beers-listed medications"],
    management: ["Conduct systematic Beers Criteria review at every annual wellness visit and at care transitions", "Deprescribe benzodiazepines: taper by 10-25% every 1-2 weeks (abrupt discontinuation causes withdrawal seizures); switch to CBT-I for insomnia, SSRI for anxiety", "Replace first-generation antihistamines (diphenhydramine) with second-generation (cetirizine, loratadine — less anticholinergic) or alternative approaches", "Switch glyburide (long-acting sulfonylurea with high hypoglycemia risk) to glipizide (shorter acting) or metformin", "Avoid meperidine entirely in elderly — use acetaminophen, low-dose short-acting opioids (morphine, hydromorphone), or topical NSAIDs instead", "Replace chronic NSAIDs with topical diclofenac for musculoskeletal pain or acetaminophen scheduled (max 3 g/day in elderly)", "Use the STOPP/START criteria alongside Beers to also identify potentially omitted beneficial medications (e.g., osteoporosis treatment, statin for secondary prevention)"],
    nursingActions: ["Perform Beers Criteria screening at every geriatric encounter — automated EHR alerts help but manual review is more comprehensive", "Calculate anticholinergic burden using ACB scale and target cumulative score <3", "Prioritize deprescribing highest-risk medications first: benzodiazepines, anticholinergics, and duplicative medications", "Use patient-centered deprescribing approach: explain rationale, provide tapering schedule, and monitor for withdrawal or symptom recurrence", "Document deprescribing rationale and plan clearly in the medical record", "Coordinate with pharmacy for comprehensive medication therapy management (MTM) reviews", "Educate patients and caregivers: 'More medications does not mean better care' — polypharmacy itself is a risk factor for adverse drug events, falls, and hospitalization"],
    assessmentFindings: ["Polypharmacy (≥5 medications) in an elderly patient", "Confusion, cognitive decline, or delirium potentially related to anticholinergic medications", "Falls or near-falls in patients on benzodiazepines, opioids, or antihypertensives", "Unexplained urinary retention, constipation, or dry mouth (anticholinergic burden)", "Recurrent hypoglycemia in elderly diabetic on glyburide or high-dose insulin", "GI bleeding or AKI in elderly patient on chronic NSAID", "Excessive sedation from cumulative CNS depressant medications"],
    signs: { left: ["Mild polypharmacy (5-7 medications) with no adverse effects identified", "Single Beers-listed medication with low-risk profile in specific patient context", "Successful benzodiazepine taper without withdrawal symptoms", "Improved cognition after anticholinergic medication discontinuation", "Patient engaged in deprescribing discussion with clear goals"], right: ["Delirium triggered by cumulative anticholinergic burden (ACB score ≥6)", "Hip fracture from benzodiazepine-related fall", "Severe hypoglycemia with seizure from glyburide in elderly with CKD", "GI hemorrhage from chronic NSAID in elderly on anticoagulation", "Meperidine-induced seizures from normeperidine accumulation in renal impairment"] },
    medications: [{ name: "Diphenhydramine (Benadryl)", type: "First-generation antihistamine (PIM)", action: "Blocks H1 receptors (antihistamine) AND muscarinic receptors (anticholinergic) — the anticholinergic properties cause significant adverse effects in elderly including confusion, delirium, urinary retention, constipation, and dry mouth", sideEffects: "Confusion and delirium, excessive sedation, falls, urinary retention, constipation, tachycardia, blurred vision; ACB score of 3 (highest)", contra: "Dementia (worsens cognition), narrow-angle glaucoma, BPH with urinary retention, concurrent anticholinergic medications", pearl: "One of the MOST commonly used inappropriate medications in elderly: available OTC in sleep aids (PM formulations), allergy medications, and cold remedies; patients often do not realize they are taking it; ALWAYS ask about OTC medications containing diphenhydramine; replace with loratadine (allergy) or melatonin/CBT-I (sleep)" }, { name: "Zolpidem (Ambien)", type: "Non-benzodiazepine hypnotic (Z-drug, PIM)", action: "Selectively binds GABA-A receptor alpha-1 subunit (responsible for sedation), producing hypnotic effect without significant anxiolytic or muscle relaxant properties", sideEffects: "Falls and hip fractures (elderly), complex sleep behaviors (sleep-driving, sleep-eating — FDA boxed warning), next-morning impairment (especially ER formulations), amnesia, paradoxical agitation", contra: "Severe hepatic impairment; Beers Criteria: avoid in all adults ≥65 due to fall risk and cognitive impairment; FDA recommends max 5 mg in women (slower metabolism)", pearl: "Listed on Beers Criteria as PIM for all elderly ≥65; falls risk equal to benzodiazepines in elderly; CBT-I (cognitive behavioral therapy for insomnia) is first-line for chronic insomnia in elderly — more effective than hypnotics long-term with no adverse effects; if pharmacotherapy needed, consider low-dose trazodone 25-50 mg or melatonin" }],
    pearls: ["The Beers Criteria is updated every 3 years by the American Geriatrics Society — the NP should be familiar with the current version and apply it at every geriatric encounter", "Anticholinergic burden is CUMULATIVE: a patient on diphenhydramine + oxybutynin + paroxetine has ACB score 9 (3+3+3), dramatically increasing delirium and cognitive decline risk", "First-generation antihistamines (diphenhydramine, hydroxyzine, chlorpheniramine) are PIMs due to anticholinergic effects — second-generation (loratadine, cetirizine, fexofenadine) are safer alternatives", "Benzodiazepine deprescribing in elderly must be GRADUAL: taper by 10-25% every 1-2 weeks over months; abrupt discontinuation after chronic use causes withdrawal seizures, even from low doses", "CBT-I (cognitive behavioral therapy for insomnia) is more effective than any pharmacotherapy for chronic insomnia in elderly and is recommended as first-line by both AGS and AASM", "The STOPP/START criteria complement Beers by also identifying medications that SHOULD be started (potentially omitted beneficial medications) — e.g., statin for secondary prevention, bisphosphonate for osteoporosis, ACEi for HFrEF", "Medication-related falls cost the US healthcare system $50 billion annually; benzodiazepines, opioids, anticholinergics, and antihypertensives are the top contributors"],
    quiz: [{ question: "A 78-year-old woman with insomnia, osteoarthritis, and allergic rhinitis takes diphenhydramine 50 mg nightly for sleep, ibuprofen 600 mg TID for pain, and zolpidem 10 mg at bedtime. How many Beers Criteria PIMs is she taking?", options: ["One PIM", "Two PIMs", "Three PIMs (all three medications)", "None — these are appropriate for her conditions"], correct: 2, rationale: "All three medications are Beers-listed PIMs: (1) Diphenhydramine — first-generation antihistamine with high anticholinergic burden, causes confusion and falls; (2) Ibuprofen chronic use — NSAID risk of GI bleeding, AKI, and heart failure in elderly; (3) Zolpidem — Z-drug with fall risk equal to benzodiazepines, complex sleep behaviors. The NP should deprescribe all three and substitute with safer alternatives: CBT-I for insomnia, topical diclofenac for pain, loratadine for allergic rhinitis." }, { question: "What is the recommended first-line treatment for chronic insomnia in adults ≥65 years according to the Beers Criteria and AASM guidelines?", options: ["Zolpidem 5 mg at bedtime", "Lorazepam 0.5 mg at bedtime", "Cognitive behavioral therapy for insomnia (CBT-I)", "Diphenhydramine 25 mg at bedtime"], correct: 2, rationale: "CBT-I is first-line for chronic insomnia in elderly per both AGS Beers Criteria and AASM guidelines. It is more effective than pharmacotherapy long-term and has no adverse effects. CBT-I includes sleep hygiene, stimulus control, sleep restriction, relaxation training, and cognitive restructuring. All sedative-hypnotics (benzodiazepines, Z-drugs, antihistamines) are PIMs in elderly due to fall risk." }, { question: "An elderly patient with type 2 diabetes on glyburide 5 mg daily has recurrent hypoglycemic episodes. What is the safer alternative?", options: ["Increase glyburide to 10 mg daily with glucose monitoring", "Switch to glipizide 5 mg daily (shorter-acting sulfonylurea with less hypoglycemia risk)", "Add metformin to allow glyburide dose reduction", "Switch to insulin glargine for tighter glucose control"], correct: 1, rationale: "Glyburide is a Beers-listed PIM in elderly due to its long half-life and active metabolites that accumulate in renal impairment, causing prolonged and severe hypoglycemia. Glipizide is the preferred sulfonylurea alternative: shorter acting, no active metabolites, and lower hypoglycemia risk. Even better options in elderly include metformin (if eGFR allows), DPP-4 inhibitors (sitagliptin), or GLP-1 agonists." }]
  },
  "geriatrics-delirium-prevention-np": {
    title: "Delirium: Prevention, Recognition & Evidence-Based Management",
    cellular: { title: "Clinical Foundation", content: "Delirium is an acute, fluctuating disturbance in attention, awareness, and cognition not better explained by a pre-existing neurocognitive disorder. It affects 15-50% of hospitalized elderly patients and is independently associated with increased mortality (10-65% in-hospital mortality), longer hospitalization (average 5-10 additional days), accelerated cognitive decline, and increased institutionalization. Three subtypes exist: hyperactive (agitation, hallucinations, restlessness — 25%), hypoactive (lethargy, withdrawal, decreased responsiveness — 50%, often missed), and mixed (fluctuating between hyper and hypoactive — 25%). The Confusion Assessment Method (CAM) is the gold standard bedside screening tool with four features: (1) acute onset and fluctuating course (required), (2) inattention (required — patient cannot recite months backward or serial 7s), (3) disorganized thinking, AND/OR (4) altered level of consciousness. Positive CAM requires features 1 AND 2 PLUS either 3 OR 4. Delirium is a medical EMERGENCY requiring identification and treatment of the underlying cause. Common precipitants follow the DELIRIUM mnemonic: Drugs (anticholinergics, benzodiazepines, opioids), Electrolyte imbalances, Lack of drugs (withdrawal), Infection (UTI, pneumonia), Reduced sensory input, Intracranial event (stroke, bleed), Urinary retention/fecal impaction, Metabolic (hypoglycemia, hepatic encephalopathy). Prevention through the Hospital Elder Life Program (HELP) reduces delirium incidence by 30-40%: orientation protocols, sleep hygiene, early mobilization, cognitive stimulation, hydration and nutrition, sensory optimization (eyeglasses, hearing aids)." },
    riskFactors: ["Age ≥65 years (strongest predisposing factor)", "Pre-existing dementia (5-fold increased delirium risk — delirium superimposed on dementia)", "Polypharmacy, especially anticholinergic and sedating medications", "Acute infection (UTI and pneumonia are the most common infectious triggers in elderly)", "Surgery (post-operative delirium in 15-53% of elderly surgical patients)", "Dehydration and malnutrition", "Sensory impairment (vision and hearing loss reduce environmental orientation)", "Urinary catheter placement (independent risk factor — promotes both infection and disorientation)"],
    diagnostics: ["Confusion Assessment Method (CAM): gold standard bedside tool — requires acute onset + inattention + (disorganized thinking OR altered consciousness)", "CAM-ICU: modified CAM for mechanically ventilated/ICU patients using nonverbal assessments", "Attention assessment: digit span, months backward, serial 7s (inattention is the cardinal feature of delirium)", "Comprehensive metabolic panel (electrolytes, glucose, renal and hepatic function)", "CBC with differential (leukocytosis suggests infection; anemia contributes to delirium)", "Urinalysis and urine culture (UTI is the most common infectious precipitant of delirium in elderly)", "Medication review (identify newly added or recently changed medications, especially anticholinergics, opioids, benzodiazepines, steroids)", "CT head (if focal neurological deficits, recent head trauma, or no identifiable cause — rule out stroke, SDH)"],
    management: ["Identify and treat the underlying cause (the ONLY definitive treatment for delirium — medication alone does not resolve delirium without addressing the precipitant)", "Non-pharmacological interventions FIRST: reorientation (clock, calendar, familiar objects), sleep-wake cycle restoration, early mobilization, cognitive stimulation, glasses and hearing aids at bedside", "Remove or minimize offending medications: discontinue anticholinergics, minimize opioids (use acetaminophen scheduled), taper benzodiazepines if not in withdrawal", "Correct metabolic derangements: hydration, electrolyte correction, glucose management, oxygenation", "Treat infections promptly (antibiotics for UTI, pneumonia; source control for surgical infections)", "Pharmacological management of severe agitation ONLY when patient is a danger to self or others: haloperidol 0.5-1 mg PO/IM (lowest effective dose, short duration); quetiapine 12.5-25 mg PO for patients with Parkinson's or Lewy body dementia", "AVOID benzodiazepines for delirium management (except alcohol/benzodiazepine withdrawal delirium — benzodiazepines are first-line in that specific context)"],
    nursingActions: ["Screen all hospitalized patients ≥65 with CAM every shift (hypoactive delirium is missed 70% of the time without systematic screening)", "Implement HELP protocol for all elderly inpatients: orientation board, clock and calendar visible, familiar objects from home, consistent staff, minimize room changes", "Maintain sleep-wake cycle: minimize nighttime interruptions, cluster care activities, reduce ambient noise and light, avoid sedating sleep medications", "Ensure sensory optimization: eyeglasses on during waking hours, hearing aids in and functioning, adequate room lighting", "Promote early mobilization: ambulate within 24 hours of admission when medically safe; physical therapy consultation", "Remove urinary catheter as soon as possible (CAUTI prevention AND delirium risk reduction)", "Avoid physical restraints (increase agitation, prolong delirium, and are associated with increased mortality in delirious patients)"],
    assessmentFindings: ["Acute change in mental status from baseline (hours to days — not gradual as in dementia)", "Fluctuating course: symptoms wax and wane throughout the day (often worse at night — 'sundowning')", "Inattention (cardinal feature): unable to focus, easily distracted, cannot maintain conversation or follow instructions", "Disorganized thinking: rambling, tangential speech, unpredictable switching between topics", "Perceptual disturbances: hallucinations (usually visual in delirium vs auditory in psychosis), misperceptions, illusions", "Psychomotor changes: hyperactive (agitation, pulling lines, combativeness) or hypoactive (lethargy, reduced responsiveness, quiet withdrawal)", "Sleep-wake cycle disturbance: daytime somnolence, nighttime agitation and insomnia"],
    signs: { left: ["Mild delirium with CAM-positive features responding to non-pharmacological measures", "Identifiable precipitant (UTI, medication) easily correctable", "Delirium resolving within 24-48 hours of precipitant treatment", "Hypoactive delirium without safety concerns", "Patient with intact baseline cognition (better prognosis for full recovery)"], right: ["Severe hyperactive delirium with combative behavior endangering patient and staff", "Delirium tremens from alcohol withdrawal (CIWA-guided benzodiazepine management)", "Delirium superimposed on advanced dementia (prolonged course, incomplete recovery)", "Persistent delirium >7 days despite treating identified precipitants (search for occult causes: meningitis, endocarditis, malignancy, status epilepticus)", "Delirium with new focal neurological deficits (stroke, intracranial hemorrhage — emergent CT)"] },
    medications: [{ name: "Haloperidol (Haldol)", type: "First-generation (typical) antipsychotic", action: "Blocks dopamine D2 receptors in the mesolimbic pathway and CTZ; provides rapid antipsychotic effect for delirium-related agitation and hallucinations without significant sedation at low doses", sideEffects: "QT prolongation (dose-dependent — obtain baseline ECG; hold if QTc >500 ms), extrapyramidal symptoms (dystonia, akathisia, parkinsonism), neuroleptic malignant syndrome (rare), tardive dyskinesia (long-term use)", contra: "Parkinson's disease (D2 blockade worsens motor symptoms), Lewy body dementia (severe neuroleptic sensitivity — life-threatening), congenital long QT syndrome, severe CNS depression", pearl: "Low-dose haloperidol (0.5-1 mg PO/IM) is reserved for severe agitation when non-pharmacological interventions fail and patient safety is at risk; NOT prophylactic; APA guidelines emphasize treating underlying cause first; AVOID in Parkinson's/Lewy body — use quetiapine 12.5 mg instead" }, { name: "Quetiapine (Seroquel)", type: "Second-generation (atypical) antipsychotic", action: "Blocks D2, 5-HT2A, H1, and alpha-1 receptors; lower D2 affinity than haloperidol makes it safer for patients with Parkinsonism or Lewy body dementia", sideEffects: "Sedation (most common — useful for agitated delirium at bedtime), orthostatic hypotension, metabolic syndrome (less relevant in acute delirium setting), QT prolongation (less than haloperidol)", contra: "Severe hepatic impairment; caution with concurrent QT-prolonging drugs; elderly patients with dementia-related psychosis (FDA black box: increased mortality, though this applies to chronic use for behavioral symptoms, not acute delirium)", pearl: "12.5-25 mg PO at bedtime for delirium agitation; preferred over haloperidol in Parkinson's disease and Lewy body dementia (lower D2 affinity causes less motor worsening); sedating properties help restore sleep-wake cycle; not available IM (use haloperidol IM if oral route unavailable)" }],
    pearls: ["Delirium is NOT normal aging — it is always caused by an underlying medical condition or medication; the NP's job is to find and treat the CAUSE, not just manage the symptoms", "Hypoactive delirium (quiet, withdrawn, lethargic) is MORE COMMON than hyperactive delirium but is missed 70% of the time without systematic CAM screening — it carries equal or worse mortality", "The CAM has >95% sensitivity and specificity when performed correctly: INATTENTION is the required cardinal feature — if the patient can maintain attention normally, it is not delirium", "AVOID benzodiazepines for delirium management (they worsen delirium) — the ONE EXCEPTION is delirium tremens (alcohol/benzodiazepine withdrawal), where benzodiazepines are the treatment of choice", "Physical restraints INCREASE agitation, prolong delirium, and are associated with increased mortality — they should be avoided; use sitters, de-escalation, and low-dose antipsychotics if absolutely necessary for safety", "The Hospital Elder Life Program (HELP) reduces delirium incidence by 30-40% through simple non-pharmacological interventions — this is the most cost-effective intervention in geriatric inpatient care", "NEVER give haloperidol or typical antipsychotics to patients with Lewy body dementia or Parkinson's disease — they have severe neuroleptic sensitivity causing irreversible parkinsonism, NMS, and death; use quetiapine 12.5 mg as the safest alternative"],
    quiz: [{ question: "A 82-year-old patient admitted for pneumonia is found lying quietly in bed, staring at the ceiling, unable to state the day or month, and not responding consistently to questions. The nurse reports this is different from his baseline. What is the most likely diagnosis and which subtype?", options: ["Depression — apathetic presentation", "Hypoactive delirium — quiet, withdrawn, inattentive with acute change from baseline", "Dementia — progressive cognitive decline", "Normal response to hospitalization in elderly"], correct: 1, rationale: "This is hypoactive delirium: acute change from baseline (hospitalized for pneumonia), inattention (cannot state date, inconsistent responses), altered level of consciousness (quietly staring). Hypoactive delirium is the most common subtype (50%) and is frequently missed because patients are quiet and 'not causing problems.' It carries equal or worse prognosis than hyperactive delirium." }, { question: "Which CAM features are BOTH required for a positive delirium screen?", options: ["Disorganized thinking AND altered consciousness", "Acute onset/fluctuating course AND inattention", "Hallucinations AND agitation", "Disorientation AND memory impairment"], correct: 1, rationale: "The CAM requires (1) acute onset with fluctuating course AND (2) inattention — BOTH are required. Additionally, either (3) disorganized thinking OR (4) altered level of consciousness must be present. Inattention is the cardinal cognitive feature of delirium: the patient cannot focus, maintain conversation, or follow a sequence of instructions." }, { question: "A delirious patient with Parkinson's disease is severely agitated and pulling at his IV and Foley catheter. Non-pharmacological interventions have failed. Which medication is safest?", options: ["Haloperidol 2 mg IM for rapid control", "Quetiapine 12.5-25 mg PO", "Lorazepam 1 mg IV for sedation", "Diphenhydramine 50 mg IV for sedation"], correct: 1, rationale: "Haloperidol is CONTRAINDICATED in Parkinson's disease — D2 blockade severely worsens motor symptoms and can trigger neuroleptic malignant syndrome. Quetiapine has lower D2 affinity and is the safest antipsychotic for Parkinson's and Lewy body dementia patients. Benzodiazepines and antihistamines would worsen delirium and are inappropriate." }]
  },

  // === CROSS-SYSTEM HIGH-YIELD (+1 to reach 8) ===
  "cross-system-sepsis-cascade-np": {
    title: "Sepsis & Septic Shock: SOFA, qSOFA & Surviving Sepsis Bundles",
    cellular: { title: "Cross-System Pathophysiology", content: "Sepsis is defined as life-threatening organ dysfunction caused by a dysregulated host response to infection (Sepsis-3, 2016). The pathophysiological cascade involves: infection triggers release of pathogen-associated molecular patterns (PAMPs: endotoxin/LPS from gram-negative bacteria, lipoteichoic acid from gram-positive) that activate innate immune cells via pattern recognition receptors (TLR-4, TLR-2). Subsequent release of pro-inflammatory cytokines (TNF-alpha, IL-1, IL-6) causes systemic inflammatory response: vasodilation (decreased SVR → hypotension), capillary leak (third-spacing → tissue edema), endothelial activation (microthrombosis → DIC, organ ischemia), and mitochondrial dysfunction (impaired cellular oxygen utilization even with adequate delivery — cytopathic hypoxia). Multi-organ dysfunction manifests as: cardiovascular (distributive shock — warm, vasodilated → then cold, vasoconstricted), pulmonary (ARDS), renal (AKI from hypoperfusion and nephrotoxic mediators), hepatic (ischemic hepatitis, coagulopathy), hematologic (DIC — thrombocytopenia, prolonged PT/aPTT, elevated D-dimer), and neurological (septic encephalopathy). The Sequential Organ Failure Assessment (SOFA) score quantifies organ dysfunction across 6 systems (respiratory, cardiovascular, hepatic, renal, coagulation, neurological); an increase of ≥2 SOFA points from baseline in the setting of infection defines sepsis. Quick SOFA (qSOFA) screens for sepsis outside the ICU: RR ≥22, altered mentation, SBP ≤100. Septic shock is defined as sepsis with persistent hypotension requiring vasopressors to maintain MAP ≥65 mmHg AND serum lactate >2 mmol/L despite adequate fluid resuscitation (mortality 40-50%)." },
    riskFactors: ["Extremes of age (<1 year and >65 years)", "Immunosuppression (chemotherapy, transplant, HIV/AIDS, chronic corticosteroids)", "Chronic comorbidities (diabetes, CKD, cirrhosis, heart failure, COPD)", "Invasive devices (central lines, urinary catheters, mechanical ventilation)", "Recent surgery or hospitalization", "Multidrug-resistant organism colonization (MRSA, VRE, ESBL-producing gram-negatives)", "Malnutrition and functional debility"],
    diagnostics: ["qSOFA at bedside (≥2 of 3: RR ≥22, altered mentation, SBP ≤100 — high specificity for sepsis outside ICU)", "SOFA score (≥2-point increase from baseline defines sepsis; calculated using PaO2/FiO2, MAP/vasopressor dose, bilirubin, platelets, creatinine, GCS)", "Serum lactate (>2 mmol/L = tissue hypoperfusion; >4 mmol/L = severe sepsis with high mortality; serial lactate clearance guides resuscitation adequacy — target ≥10% decrease per 2 hours)", "Blood cultures x2 (from 2 separate sites BEFORE antibiotics, but do NOT delay antibiotics for culture collection — draw within minutes)", "Procalcitonin (>0.5 ng/mL supports bacterial infection; useful for antibiotic stewardship — guide de-escalation when trending down)", "CBC with differential (leukocytosis or leukopenia, left shift/bandemia, thrombocytopenia in DIC)", "Comprehensive metabolic panel (renal function, hepatic function, glucose), coagulation studies (PT, aPTT, fibrinogen, D-dimer for DIC assessment)"],
    management: ["Hour-1 Bundle (Surviving Sepsis Campaign 2021): (1) Measure lactate, (2) Obtain blood cultures before antibiotics, (3) Administer broad-spectrum antibiotics within 1 hour, (4) Begin IV crystalloid 30 mL/kg for hypotension or lactate ≥4, (5) Apply vasopressors if hypotensive during or after fluid resuscitation to target MAP ≥65", "Broad-spectrum empiric antibiotics: community-acquired — piperacillin-tazobactam or cefepime + vancomycin (if MRSA risk); healthcare-associated — meropenem + vancomycin", "Norepinephrine: first-line vasopressor for septic shock (target MAP ≥65 mmHg); add vasopressin 0.03 units/min as second agent if norepinephrine dose exceeds 0.25 mcg/kg/min", "IV fluid resuscitation: initial bolus 30 mL/kg balanced crystalloid (LR preferred over NS); reassess with point-of-care ultrasound (IVC collapsibility, cardiac function) before additional fluids", "Source control within 6-12 hours: drain abscesses, remove infected devices, debride necrotic tissue", "Stress-dose hydrocortisone 200 mg/day (50 mg q6h IV) for refractory septic shock (hypotension unresponsive to adequate fluids + norepinephrine ≥0.25 mcg/kg/min)", "De-escalate antibiotics once culture results and sensitivities are available — target 7-day antibiotic course for most infections (procalcitonin-guided de-escalation)"],
    nursingActions: ["Screen for sepsis using qSOFA in any patient with suspected infection: RR ≥22, altered mentation, SBP ≤100 (≥2 positive = activate sepsis protocol)", "Implement Hour-1 Bundle immediately: draw lactate and blood cultures, start IV crystalloid 30 mL/kg, administer broad-spectrum antibiotics within 1 hour of recognition", "Draw blood cultures from 2 separate venipuncture sites BEFORE antibiotic administration (but do NOT delay antibiotics beyond minutes if cultures are difficult to obtain)", "Monitor serial lactate every 2-4 hours: target ≥10% decrease per 2 hours (lactate clearance is the best marker of adequate resuscitation)", "Titrate vasopressors (norepinephrine) to target MAP ≥65 mmHg: use central line for high-dose vasopressors; peripheral norepinephrine is acceptable temporarily while central access is obtained", "Assess volume responsiveness before additional fluid boluses: passive leg raise test, IVC ultrasound, pulse pressure variation — fluid overload worsens ARDS and outcomes", "Monitor for multi-organ dysfunction: urine output (<0.5 mL/kg/hr = renal), altered consciousness (neurological), coagulopathy (DIC), rising bilirubin (hepatic), PaO2/FiO2 decline (pulmonary)"],
    assessmentFindings: ["Fever >38.3°C or hypothermia <36°C (hypothermia in sepsis = poor prognosis)", "Tachycardia >90 bpm and tachypnea >22 breaths/min", "Hypotension: SBP <100 mmHg or MAP <65 mmHg (septic shock if requiring vasopressors)", "Altered mental status (septic encephalopathy — confusion, agitation, lethargy)", "Warm, flushed skin initially (distributive shock: vasodilation) → cool, mottled, cyanotic late (vasoconstriction from sympathetic compensation)", "Oliguria (<0.5 mL/kg/hr) indicating renal hypoperfusion", "Elevated lactate (>2 mmol/L = tissue hypoperfusion; >4 mmol/L = severe sepsis)"],
    signs: { left: ["Sepsis without shock: infection + SOFA ≥2 with adequate blood pressure", "Lactate 2-4 mmol/L clearing with initial fluid resuscitation", "Hypotension responsive to 30 mL/kg crystalloid bolus without vasopressors", "Source identified and controlled within 6 hours", "Appropriate antibiotic coverage with cultures pending"], right: ["Septic shock: MAP <65 requiring vasopressors AND lactate >2 despite fluids (mortality 40-50%)", "Refractory septic shock requiring multiple vasopressors and stress-dose steroids", "DIC with active bleeding (thrombocytopenia, prolonged PT/aPTT, elevated D-dimer, low fibrinogen)", "Multi-organ dysfunction syndrome (MODS): ARDS + AKI + hepatic failure + DIC", "Lactate >8 mmol/L and rising despite maximal resuscitation (mortality >80%)"] },
    medications: [{ name: "Norepinephrine (Levophed)", type: "First-line vasopressor (alpha-1 > beta-1 adrenergic agonist)", action: "Potent alpha-1 agonist causing arterial vasoconstriction (increases SVR and MAP) with moderate beta-1 activity (increases cardiac contractility and heart rate); restores organ perfusion pressure in distributive shock", sideEffects: "Tissue ischemia (digital, mesenteric) at high doses, arrhythmias, reflex bradycardia, extravasation necrosis (requires central line; phentolamine for extravasation treatment)", contra: "No absolute contraindications in septic shock (life-saving); relative: mesenteric ischemia, severe peripheral vascular disease", pearl: "First-line vasopressor per Surviving Sepsis Campaign: start at 0.05-0.1 mcg/kg/min, titrate to MAP ≥65; if dose exceeds 0.25 mcg/kg/min, add vasopressin 0.03 units/min as second agent; can run temporarily through peripheral IV (large-bore antecubital) while obtaining central access; phentolamine 5-10 mg in 10 mL NS infiltrated locally for extravasation" }, { name: "Hydrocortisone (stress-dose)", type: "Glucocorticoid (adrenal support in refractory shock)", action: "Replaces cortisol in relative adrenal insufficiency of sepsis (critical illness-related corticosteroid insufficiency); restores vascular sensitivity to catecholamines, reduces inflammatory cytokine production, and improves hemodynamics", sideEffects: "Hyperglycemia (most common — monitor glucose every 4-6 hours), immunosuppression (relative), hypernatremia, secondary infections, GI bleeding (rare at stress doses)", contra: "No absolute contraindications in refractory septic shock; relative: active fungal infection, uncontrolled hyperglycemia", pearl: "200 mg/day IV (50 mg q6h or continuous infusion) for refractory septic shock (vasopressor-dependent MAP <65 despite norepinephrine ≥0.25 mcg/kg/min + adequate fluid resuscitation); APROCCHSS trial: reduced 90-day mortality; do NOT use routine random cortisol or cosyntropin stimulation test to guide therapy — give empirically based on hemodynamic criteria" }],
    pearls: ["The Hour-1 Bundle is the most critical intervention in sepsis: every hour of delay in antibiotic administration after sepsis recognition increases mortality by 7.6% (Kumar et al. landmark study)", "Lactate is not just a marker of anaerobic metabolism — in sepsis, elevated lactate also results from catecholamine-driven aerobic glycolysis, mitochondrial dysfunction, and reduced hepatic clearance; regardless of mechanism, elevated and rising lactate = poor prognosis", "qSOFA (RR ≥22, altered mentation, SBP ≤100) is designed for bedside SCREENING outside the ICU — it is NOT a diagnostic tool and should not replace SOFA score for defining sepsis", "Balanced crystalloid (Lactated Ringer's) is preferred over normal saline for sepsis resuscitation: the SMART trial showed reduced renal adverse events and mortality with balanced crystalloid; NS causes hyperchloremic metabolic acidosis with large volumes", "Norepinephrine is first-line vasopressor — dopamine is no longer recommended due to increased arrhythmia risk without survival benefit (De Backer et al., SOAP II trial)", "Do NOT target MAP >65 in all patients: the SEPSISPAM trial showed no benefit to targeting MAP 80-85 vs 65-70 except in patients with chronic hypertension (consider higher MAP target 75-80 in chronic HTN)", "Fluid overload is harmful in sepsis: after initial 30 mL/kg bolus, reassess with dynamic parameters (PLR, IVC ultrasound) before additional fluids — excessive fluid worsens ARDS, prolongs mechanical ventilation, and increases mortality"],
    quiz: [{ question: "A patient with pneumonia has temperature 39.2°C, heart rate 112, RR 26, BP 82/50, altered mental status, and lactate 5.8 mmol/L. What is the FIRST priority in the Hour-1 Bundle?", options: ["Obtain CT chest to assess pneumonia severity", "Draw blood cultures AND start broad-spectrum IV antibiotics within 1 hour while initiating 30 mL/kg crystalloid bolus", "Consult infectious disease before starting antibiotics", "Start norepinephrine immediately before IV fluids"], correct: 1, rationale: "The Hour-1 Bundle requires simultaneous actions: draw blood cultures (from 2 sites), start broad-spectrum antibiotics (within 1 hour — do NOT delay for cultures if difficult), initiate 30 mL/kg crystalloid resuscitation, and measure lactate. Every hour of antibiotic delay increases mortality by 7.6%. CT can be obtained after stabilization. Vasopressors are started if hypotension persists after fluid resuscitation." }, { question: "After receiving 30 mL/kg crystalloid, a septic shock patient remains hypotensive (MAP 58 mmHg). What is the first-line vasopressor?", options: ["Dopamine 5-10 mcg/kg/min", "Norepinephrine 0.05-0.1 mcg/kg/min titrated to MAP ≥65 mmHg", "Epinephrine 0.1 mcg/kg/min", "Phenylephrine 100-200 mcg/min"], correct: 1, rationale: "Norepinephrine is the first-line vasopressor for septic shock per the Surviving Sepsis Campaign guidelines. It provides both alpha-1 (vasoconstriction to increase MAP) and beta-1 (positive inotropy) effects. Dopamine is no longer recommended due to higher arrhythmia risk (SOAP II trial). Vasopressin (0.03 units/min) is added as the second agent if norepinephrine dose exceeds 0.25 mcg/kg/min." }, { question: "A septic shock patient on norepinephrine 0.4 mcg/kg/min and vasopressin 0.03 units/min remains hypotensive (MAP 60). What adjunctive therapy should the NP initiate?", options: ["Increase norepinephrine to 1.0 mcg/kg/min", "Add stress-dose hydrocortisone 50 mg IV q6h", "Switch to dopamine for renal-dose protection", "Start dobutamine for cardiac augmentation"], correct: 1, rationale: "Refractory septic shock (persistent hypotension despite adequate fluids + norepinephrine ≥0.25 mcg/kg/min + vasopressin) is the indication for stress-dose hydrocortisone (200 mg/day = 50 mg q6h IV). The APROCCHSS trial demonstrated reduced 90-day mortality in refractory septic shock. Hydrocortisone restores vascular catecholamine sensitivity and addresses relative adrenal insufficiency." }]
  },

  // === HIGH-YIELD NP EXAM PATTERNS (+1 to reach 8) ===
  "hy-exam-first-worst-presentations-np": {
    title: "First & Worst Presentations: Emergency Differential Diagnosis Patterns",
    cellular: { title: "Clinical Reasoning", content: "The NP certification exam and clinical practice frequently test 'first and worst' presentation patterns — scenarios where patients present with the first episode or worst episode of a symptom, requiring the NP to systematically rule out life-threatening etiologies before diagnosing benign conditions. The 'worst headache of my life' mandates subarachnoid hemorrhage (SAH) evaluation: CT head (sensitivity 95% within 6 hours, drops to 50% at 1 week) → if negative, lumbar puncture for xanthochromia (gold standard for SAH beyond 6-12 hours); do NOT attribute to migraine without CT/LP. 'Tearing chest pain radiating to the back' mandates aortic dissection evaluation: CT angiography of chest/abdomen/pelvis (sensitivity >95%); do NOT give thrombolytics (fatal if dissection mistaken for MI). First seizure in an adult requires neuroimaging (CT or MRI) and EEG — new-onset seizures in adults >40 must exclude brain tumor, stroke, or metabolic causes. 'Worst abdominal pain' with rigid abdomen requires surgical evaluation: CT abdomen for perforated viscus, mesenteric ischemia, ruptured AAA, or bowel obstruction. Acute monocular vision loss mandates emergent evaluation: temporal arteritis (ESR/CRP, immediate high-dose prednisone), central retinal artery occlusion (90-minute window for reperfusion), or retinal detachment (curtain or veil over vision). The systematic approach for all 'first and worst' presentations: (1) stabilize (ABC), (2) identify and rule out life-threatening diagnoses first, (3) NEVER anchor on a benign diagnosis without excluding emergencies, (4) document your differential and rationale for workup." },
    riskFactors: ["Sudden onset of maximal-intensity symptoms (thunderclap onset = vascular emergency until proven otherwise)", "New neurological deficits accompanying pain (stroke, dissection, SAH)", "Age >40 with first-ever seizure (structural brain lesion must be excluded)", "Chest pain with hemodynamic instability (MI, PE, aortic dissection, tension pneumothorax)", "Abdominal pain with peritoneal signs (rigidity, guarding, rebound = surgical abdomen)", "Acute vision loss (vascular emergency or temporal arteritis — irreversible without immediate treatment)", "Immunocompromised patients with new symptoms (broader differential, atypical presentations)"],
    diagnostics: ["Worst headache: non-contrast CT head (SAH detection: 95% at 6 hours, decreasing with time) → LP for xanthochromia if CT negative", "Tearing chest/back pain: CT angiography chest/abdomen/pelvis for aortic dissection (type A involves ascending aorta = surgical emergency; type B = descending = medical management)", "First seizure adult: brain MRI with contrast + EEG (brain tumor, stroke, vascular malformation, encephalitis)", "Acute abdomen: CT abdomen/pelvis with IV contrast (free air = perforation; pneumatosis intestinalis = ischemic bowel; absent contrast enhancement = mesenteric ischemia)", "Acute monocular vision loss: ESR and CRP (temporal arteritis: ESR >50 mm/hr typically); dilated fundoscopic exam; immediate ophthalmology consult", "Acute limb ischemia: CTA of affected extremity (6 P's assessment: pain, pallor, pulselessness, paresthesia, paralysis, poikilothermia)", "Syncope with exertion: echocardiogram (hypertrophic cardiomyopathy, aortic stenosis, pulmonary hypertension — all can cause exertional syncope/sudden death)"],
    management: ["SAH confirmed: emergent neurosurgical consult for aneurysm securing (surgical clipping or endovascular coiling); nimodipine 60 mg q4h for vasospasm prevention; BP control", "Aortic dissection: type A (ascending) = emergent surgical repair; type B (descending) = IV esmolol (target HR <60, SBP 100-120); do NOT give anticoagulation or thrombolytics", "First seizure: start AED only if high recurrence risk (abnormal EEG, structural lesion, focal seizure, status epilepticus); treat underlying cause if identified", "Peritonitis/surgical abdomen: nothing by mouth, IV fluid resuscitation, broad-spectrum antibiotics, emergent surgical consult", "Temporal arteritis: start prednisone 60-80 mg daily IMMEDIATELY (do not wait for biopsy — vision loss is irreversible); temporal artery biopsy within 2 weeks (steroids do not affect biopsy for 1-2 weeks)", "Central retinal artery occlusion: emergent ophthalmology consult within 90 minutes; digital ocular massage, anterior chamber paracentesis, inhaled carbogen — limited evidence but time-critical", "Mesenteric ischemia: emergent vascular surgery consult; anticoagulation; revascularization (surgical or endovascular); resection of necrotic bowel"],
    nursingActions: ["Apply the 'worst-first' principle: always evaluate for the most dangerous diagnosis first before considering benign explanations", "For thunderclap headache: order non-contrast CT head immediately; if negative, perform LP for xanthochromia — NEVER discharge a 'worst headache of my life' without CT and LP", "For tearing chest pain: think aortic dissection before MI; check bilateral arm blood pressures (>20 mmHg difference suggests dissection); order CT angiography, NOT thrombolytics", "For first seizure in adults >40: assume structural brain lesion until MRI proves otherwise; order brain MRI with contrast + EEG", "For acute monocular vision loss in elderly: check ESR and CRP immediately; start high-dose prednisone (60-80 mg) BEFORE temporal artery biopsy if GCA suspected", "For acute abdomen with peritoneal signs: NPO, IV access, labs (CBC, lactate, lipase, LFTs), CT abdomen, surgical consult — do NOT wait for imaging to call surgery if peritonitis is obvious", "Document differential diagnosis explicitly in the chart for all 'first and worst' presentations — this demonstrates clinical reasoning and medicolegal thoroughness"],
    assessmentFindings: ["Thunderclap headache: maximal intensity within seconds to minutes (SAH, reversible cerebral vasoconstriction syndrome, pituitary apoplexy)", "Tearing interscapular pain with blood pressure differential between arms (aortic dissection)", "Rigid abdomen with absent bowel sounds and rebound tenderness (peritonitis)", "Acute monocular vision loss: painless (CRAO: pale retina, cherry-red spot; temporal arteritis: with jaw claudication, temporal tenderness, elevated ESR)", "New-onset focal seizure in adult >40 without prior seizure history (brain tumor, stroke, AVM)", "Exertional syncope in young athlete (hypertrophic cardiomyopathy, anomalous coronary artery — risk of sudden cardiac death)", "Acute severe leg pain with absent pulses and mottled skin (acute limb ischemia — 6 P's)"],
    signs: { left: ["Headache with normal CT and normal LP (migraine, tension headache — benign after life threats excluded)", "First seizure with normal MRI, normal EEG, and identifiable trigger (alcohol withdrawal, hypoglycemia)", "Mild abdominal pain with normal labs and imaging (functional pain, IBS)", "Transient visual disturbance that resolves completely within minutes (migraine aura, amaurosis fugax — still warrants workup)", "Syncope in young person with normal ECG and echo (vasovagal — benign)"], right: ["Thunderclap headache with SAH on CT or xanthochromia on LP (aneurysm rupture)", "Type A aortic dissection with hemopericardium and tamponade (emergent surgery)", "Acute mesenteric ischemia with bowel necrosis and peritonitis (surgical emergency, high mortality)", "Giant cell arteritis with acute vision loss progressing to bilateral blindness without immediate steroids", "Exertional syncope with asymmetric septal hypertrophy on echo (HCM — sudden death risk)"] },
    medications: [{ name: "Nimodipine", type: "Dihydropyridine calcium channel blocker (selective cerebral vasodilator)", action: "Selectively dilates cerebral arteries, preventing and treating vasospasm after subarachnoid hemorrhage — the leading cause of morbidity in SAH survivors", sideEffects: "Hypotension (dose-dependent), headache, nausea, bradycardia (less than other CCBs)", contra: "Severe hypotension, concurrent IV calcium channel blocker administration", pearl: "60 mg PO or via NG tube every 4 hours for 21 days after SAH; MUST be given orally/enterally — IV nimodipine has been given orally by mistake causing fatal hypotension (enteral syringe only); reduces vasospasm-related poor outcomes by 40% but does NOT reduce vasospasm incidence — neuroprotective mechanism; start within 96 hours of SAH" }, { name: "Esmolol", type: "Ultra-short-acting beta-1 selective blocker", action: "Blocks beta-1 receptors, reducing heart rate and contractility; decreases aortic wall shear stress (dP/dt) in aortic dissection — the primary hemodynamic target", sideEffects: "Bradycardia, hypotension, bronchospasm (beta-1 selective but may affect beta-2 at high doses), injection site irritation", contra: "Severe bradycardia, heart block, decompensated heart failure, severe asthma", pearl: "First-line IV anti-impulse therapy for acute aortic dissection: loading dose 500 mcg/kg over 1 min, then 50-200 mcg/kg/min infusion; target HR <60 bpm AND SBP 100-120 mmHg; ultra-short half-life (9 min) allows rapid titration; add IV nicardipine if additional BP control needed after HR is controlled; ALWAYS control HR before adding vasodilator (vasodilator alone causes reflex tachycardia, increasing aortic shear stress)" }],
    pearls: ["The 'worst headache of my life' mandates SAH evaluation: CT head (sensitivity 95% at 6 hours) → LP for xanthochromia if CT negative; NEVER discharge without completing both steps", "In aortic dissection: ALWAYS control heart rate BEFORE blood pressure — reducing BP alone causes reflex tachycardia, increasing aortic wall shear stress (dP/dt) and propagating the dissection", "Type A aortic dissection (ascending aorta) = emergent surgical repair (mortality increases 1-2% per hour without surgery); Type B (descending only) = medical management with IV beta-blocker + vasodilator", "Temporal arteritis: start prednisone 60-80 mg daily IMMEDIATELY if clinical suspicion is high — do NOT wait for biopsy; vision loss is irreversible; biopsy remains positive for 1-2 weeks after starting steroids", "New-onset seizure in adults >40 is a brain tumor until proven otherwise — brain MRI with contrast is mandatory; common tumors: glioblastoma, metastases (lung, breast, melanoma)", "Exertional syncope in a young athlete should NEVER be attributed to dehydration without cardiac evaluation — hypertrophic cardiomyopathy is the leading cause of sudden cardiac death in athletes <35", "The 'acute abdomen' with peritoneal signs (rigidity, guarding, rebound tenderness) is a surgical emergency — diagnostic imaging should not delay surgical consultation"],
    quiz: [{ question: "A 55-year-old presents with 'the worst headache of my life' that reached maximum intensity within 30 seconds. Non-contrast CT head performed at 4 hours is negative. What is the next step?", options: ["Diagnose migraine and discharge with triptans", "Perform lumbar puncture to evaluate for xanthochromia (SAH not excluded by negative CT)", "Order CT angiography to visualize cerebral aneurysms", "Prescribe opioids for pain control and follow up in 1 week"], correct: 1, rationale: "A negative CT head does NOT exclude SAH — CT sensitivity drops from 95% at 6 hours to 50% at 1 week. Lumbar puncture for xanthochromia (yellow discoloration from bilirubin breakdown of blood) is the gold standard when CT is negative but clinical suspicion remains high. If LP shows xanthochromia, CT angiography is then performed to identify the aneurysm. NEVER discharge a thunderclap headache without completing the CT → LP algorithm." }, { question: "A patient presents with sudden tearing chest pain radiating to the back and a 30 mmHg blood pressure difference between arms. Troponin is mildly elevated. What is the priority diagnosis to exclude?", options: ["ST-elevation myocardial infarction", "Acute aortic dissection", "Pulmonary embolism", "Esophageal rupture"], correct: 1, rationale: "Tearing chest/back pain with blood pressure differential between arms is the classic presentation of aortic dissection. The mildly elevated troponin can occur in dissection (coronary ostia involvement or demand ischemia) — this is a critical distinction because giving thrombolytics or anticoagulation for presumed MI in a dissection patient is FATAL. The priority is CT angiography to evaluate for dissection before any anticoagulation." }, { question: "A 72-year-old woman with temporal headache, jaw claudication, and acute monocular vision loss has ESR 92 mm/hr and CRP 45 mg/L. What is the immediate treatment?", options: ["Schedule temporal artery biopsy and await results before treatment", "Start prednisone 60-80 mg daily immediately without waiting for biopsy", "Prescribe aspirin 325 mg daily and refer to ophthalmology next week", "Order MRI brain to evaluate for stroke"], correct: 1, rationale: "This is giant cell (temporal) arteritis with acute vision loss — a medical emergency. High-dose prednisone (60-80 mg daily) must be started IMMEDIATELY to prevent irreversible bilateral blindness. Temporal artery biopsy should be performed within 2 weeks to confirm the diagnosis, but treatment MUST NOT be delayed for biopsy. Steroids do not affect biopsy results for 1-2 weeks, providing an adequate diagnostic window." }]
  }
};
